import { calculateGraphSize } from './calculate-graph-size.js';
import { MIN_LEGEND_WIDTH } from '../types/constants.js';

const getAreasWidthSizeHandler = (
  containerHeight: number,
  containerWidth: number,
  maxWidth: number,
  resizerWrapperSize: number,
  legendInitialWidth: number,
) => {
  const maxAllowedLegendWidth = containerWidth * maxWidth;
  const legendWidth =
    legendInitialWidth > maxAllowedLegendWidth
      ? maxAllowedLegendWidth
      : Math.max(legendInitialWidth, MIN_LEGEND_WIDTH);

  const legend = {
    height: containerHeight,
    width: legendWidth,
  };

  const graph = {
    width: calculateGraphSize(containerWidth, legendWidth, resizerWrapperSize),
    height: containerHeight,
  };

  return { legend, graph };
};

const getAreasHeightSizeHandler = (
  containerHeight: number,
  containerWidth: number,
  maxHeight: number,
  resizerWrapperSize: number,
  legendInitialHeight: number,
) => {
  const maxAllowedLegendHeight = containerHeight * maxHeight;
  const legendHeight =
    legendInitialHeight > maxAllowedLegendHeight
      ? maxAllowedLegendHeight
      : legendInitialHeight;
  const legend = {
    height: legendHeight,
    width: containerWidth,
  };

  const graph = {
    width: containerWidth,
    height: calculateGraphSize(
      containerHeight,
      legendHeight,
      resizerWrapperSize,
    ),
  };

  return {
    legend,
    graph,
  };
};

export const getAreasSizeHandlers = (
  containerHeight: number,
  containerWidth: number,
  resizerWrapperSize: number,
) => ({
  getAreasHeightSize: (maxHeight: number, legendInitialHeight: number) =>
    getAreasHeightSizeHandler(
      containerHeight,
      containerWidth,
      maxHeight,
      resizerWrapperSize,
      legendInitialHeight,
    ),
  getAreasWidthSize: (maxWidth: number, legendInitialWidth: number) =>
    getAreasWidthSizeHandler(
      containerHeight,
      containerWidth,
      maxWidth,
      resizerWrapperSize,
      legendInitialWidth,
    ),
});
